from flask import Flask, redirect, request, session, url_for
import requests
import jwt
import os
import uuid

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://provider.com/oauth2/authorize'
TOKEN_ENDPOINT = 'https://provider.com/oauth2/token'
USERINFO_ENDPOINT = 'https://provider.com/userinfo'
SCOPE = 'openid profile email'

@app.route('/')
def index():
    return 'Welcome to the Flask OpenID Connect App! <a href="/login">Login</a>'

@app.route('/login')
def login():
    nonce = str(uuid.uuid4())
    session['nonce'] = nonce
    authorization_url = f"{AUTHORIZATION_ENDPOINT}?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope={SCOPE}&nonce={nonce}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    nonce = session.pop('nonce', None)

    token_response = requests.post(TOKEN_ENDPOINT, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })
    
    tokens = token_response.json()
    id_token = tokens.get('id_token')

    if id_token:
        decoded_token = jwt.decode(id_token, options={"verify_signature": False})
        if decoded_token.get('nonce') != nonce:
            return "Invalid nonce", 400
        
        session['user'] = {
            'sub': decoded_token.get('sub'),
            'name': decoded_token.get('name'),
            'email': decoded_token.get('email')
        }
        return redirect(url_for('profile'))
    
    return "Authentication failed", 400

@app.route('/profile')
def profile():
    user = session.get('user')
    if user:
        return f"Hello, {user['name']}! Your email is {user['email']}."
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)